import { guardProcessEnv } from "./helpers/env-guard.js";
guardProcessEnv();

/**
 * Contract tests for Bobbit's Pi 0.81 AuthInteraction adapter.
 *
 * The Models dependency is injected only at its login boundary, allowing
 * these tests to drive the exact prompt/notify contract passed to Models.login()
 * without opening Pi's local callback server or using the network.
 */
import { afterAll, beforeEach, describe, it, vi } from "vitest";
import assert from "node:assert/strict";
import { existsSync, mkdirSync, mkdtempSync, readFileSync, rmSync } from "node:fs";
import { tmpdir } from "node:os";
import path from "node:path";
import type { AuthInteraction, Credential, Models, OAuthCredential } from "@earendil-works/pi-ai";
import { resetAgentDirStateForTests } from "../../src/server/bobbit-dir.js";

const piMocks = {
	login: vi.fn(),
};

const tmp = mkdtempSync(path.join(tmpdir(), "bobbit-oauth-cb-"));
const agentDir = path.join(tmp, "agent");
const authPath = path.join(agentDir, "auth.json");
mkdirSync(agentDir, { recursive: true });
process.env.BOBBIT_AGENT_DIR = agentDir;
resetAgentDirStateForTests();

const {
	oauthComplete,
	oauthFlowStatus,
	oauthStart,
	stopFlowCleanup,
} = await import("../../src/server/auth/oauth.js");

const fakeModels = (): Pick<Models, "login"> => ({
	login: piMocks.login as unknown as Models["login"],
});
const startExternal = () => oauthStart("openai-codex", undefined, fakeModels());

interface LoginCapture {
	providerId?: string;
	type?: string;
	interaction?: AuthInteraction;
	resolve?: (credential: Credential) => void;
	reject?: (error: Error) => void;
}

function installPendingLogin(capture: LoginCapture): void {
	piMocks.login.mockImplementation(
		(providerId: string, type: string, interaction: AuthInteraction) => {
			capture.providerId = providerId;
			capture.type = type;
			capture.interaction = interaction;
			return new Promise<Credential>((resolve, reject) => {
				capture.resolve = resolve;
				capture.reject = reject;
			});
		},
	);
}

async function waitForInteraction(capture: LoginCapture): Promise<AuthInteraction> {
	for (let i = 0; i < 100 && !capture.interaction; i++) {
		await new Promise((resolve) => setTimeout(resolve, 5));
	}
	assert.ok(capture.interaction, "Models.login() should receive an AuthInteraction");
	return capture.interaction;
}

async function rejectPendingLogin(capture: LoginCapture, flowId: string): Promise<void> {
	capture.reject?.(new Error("test teardown"));
	await new Promise((resolve) => setTimeout(resolve, 0));
	oauthFlowStatus(flowId, "openai-codex");
}

beforeEach(() => {
	piMocks.login.mockReset();
	rmSync(authPath, { force: true });
});

afterAll(() => {
	stopFlowCleanup();
	rmSync(tmp, { recursive: true, force: true });
});

describe("oauthStartExternal — Pi 0.81 AuthInteraction contract", () => {
	it("calls Models.login and maps a device-code notification to the start response", async () => {
		const capture: LoginCapture = {};
		installPendingLogin(capture);

		const startPromise = startExternal();
		const interaction = await waitForInteraction(capture);
		assert.equal(capture.providerId, "openai-codex");
		assert.equal(capture.type, "oauth");
		assert.ok(interaction.signal instanceof AbortSignal);

		interaction.notify({
			type: "device_code",
			userCode: "ABCD-1234",
			verificationUri: "https://example.test/device",
			intervalSeconds: 5,
			expiresInSeconds: 600,
		});

		const started = await startPromise;
		assert.equal(started.url, "https://example.test/device");
		assert.equal(started.callbackServer, true);
		assert.match(started.instructions ?? "", /ABCD-1234/);
		assert.match(started.instructions ?? "", /https:\/\/example\.test\/device/);

		await rejectPendingLogin(capture, started.flowId);
	});

	it("selects deterministic/browser options and rejects unsupported prompts loudly", async () => {
		const capture: LoginCapture = {};
		installPendingLogin(capture);

		const startPromise = startExternal();
		const interaction = await waitForInteraction(capture);
		interaction.notify({ type: "auth_url", url: "https://example.test/auth" });
		const started = await startPromise;

		assert.equal(await interaction.prompt({
			type: "select",
			message: "Pick an org",
			options: [{ id: "org-1", label: "Only Org" }],
		}), "org-1");

		assert.equal(await interaction.prompt({
			type: "select",
			message: "Select OpenAI Codex login method:",
			options: [
				{ id: "browser", label: "Browser login (default)" },
				{ id: "device_code", label: "Device code login (headless)" },
			],
		}), "browser");

		assert.equal(await interaction.prompt({
			type: "select",
			message: "Choose a login method",
			options: [
				{ id: "web_callback", label: "Browser based login" },
				{ id: "headless", label: "Headless login" },
			],
		}), "web_callback");

		await assert.rejects(
			interaction.prompt({
				type: "select",
				message: "Pick one",
				options: [
					{ id: "a", label: "Option A" },
					{ id: "b", label: "Option B" },
				],
			}),
			/does not support/i,
		);
		await assert.rejects(
			interaction.prompt({ type: "secret", message: "Enter a secret" }),
			/unsupported secret prompt.*does not support/i,
		);

		await rejectPendingLogin(capture, started.flowId);
	});

	it("keeps start resolution one-shot and redacts lifecycle logs", async () => {
		const capture: LoginCapture = {};
		installPendingLogin(capture);
		const log = vi.spyOn(console, "log").mockImplementation(() => {});

		try {
			const startPromise = startExternal();
			const interaction = await waitForInteraction(capture);
			interaction.notify({
				type: "auth_url",
				url: "https://example.test/auth",
				instructions: "Open this URL",
			});
			const started = await startPromise;

			assert.doesNotThrow(() => interaction.notify({
				type: "device_code",
				userCode: "LATER",
				verificationUri: "https://example.test/later",
			}));
			assert.equal(started.url, "https://example.test/auth");
			assert.equal(started.instructions, "Open this URL");

			interaction.notify({ type: "progress", message: "access_token=super-secret-value" });
			interaction.notify({ type: "info", message: "Bearer another-secret-token" });
			const output = log.mock.calls.flat().join(" ");
			assert.doesNotMatch(output, /super-secret-value|another-secret-token/);
			assert.match(output, /redacted-token/);

			await rejectPendingLogin(capture, started.flowId);
		} finally {
			log.mockRestore();
		}
	});

	it("feeds text/manual prompts from oauthComplete and stores returned credentials", async () => {
		const credentials: OAuthCredential = {
			type: "oauth",
			access: "stored-access",
			refresh: "stored-refresh",
			expires: 123456789,
			accountId: "account-1",
		};
		let seenText: string | undefined;
		let seenManual: string | undefined;

		piMocks.login.mockImplementation(
			async (providerId: string, type: string, interaction: AuthInteraction): Promise<Credential> => {
				assert.equal(providerId, "openai-codex");
				assert.equal(type, "oauth");
				interaction.notify({
					type: "auth_url",
					url: "https://example.test/auth",
					instructions: "Complete login",
				});
				[seenText, seenManual] = await Promise.all([
					interaction.prompt({ type: "text", message: "Paste code" }),
					interaction.prompt({ type: "manual_code", message: "Paste redirect URL" }),
				]);
				return credentials;
			},
		);

		const started = await startExternal();
		assert.equal(started.callbackServer, true);
		const completed = await oauthComplete(started.flowId, "  pasted-code  ");
		assert.deepEqual(completed, { success: true });
		assert.equal(seenText, "pasted-code");
		assert.equal(seenManual, "pasted-code");
		assert.equal(existsSync(authPath), true);
		assert.deepEqual(JSON.parse(readFileSync(authPath, "utf8"))["openai-codex"], credentials);
	});

	it("expires a pending prompt and aborts the Models.login interaction", async () => {
		let interactionSeen: AuthInteraction | undefined;
		let promptError: unknown;
		piMocks.login.mockImplementation(
			async (_providerId: string, _type: string, interaction: AuthInteraction): Promise<Credential> => {
				interactionSeen = interaction;
				interaction.notify({ type: "auth_url", url: "https://example.test/auth" });
				try {
					await interaction.prompt({ type: "manual_code", message: "Paste code" });
				} catch (error) {
					promptError = error;
					throw error;
				}
				throw new Error("prompt unexpectedly resolved");
			},
		);

		const started = await startExternal();
		const now = Date.now();
		const dateNow = vi.spyOn(Date, "now").mockReturnValue(now + 6 * 60 * 1000);
		try {
			assert.deepEqual(await oauthComplete(started.flowId, "too-late"), {
				success: false,
				error: "OAuth flow expired",
			});
		} finally {
			dateNow.mockRestore();
		}
		for (let i = 0; i < 20 && !promptError; i++) await Promise.resolve();
		assert.ok(interactionSeen?.signal?.aborted);
		assert.match(promptError instanceof Error ? promptError.message : String(promptError), /OAuth flow expired/);
	});
});
